--Variables de filtro setear a las fechas deseadas
declare @fechaInicioFiltro datetime
declare @fechaFinFiltro datetime
declare @usuarioFiltro varchar(max)

set @fechaInicioFiltro = '2026-03-13'
set @fechaFinFiltro = getdate()+1
set @usuarioFiltro = '%'	--poner % si no se quiere filtrar por usuario

--Variables auxiliares
declare @sql nvarchar(max)
declare @cursorIdPkFieldAux varchar(750)
declare @camposFormateados nvarchar(max)
declare @campoAux nvarchar(max)
declare @tipoDatoCampoAux varchar(255)
declare @sentenciaReplace nvarchar(max)
declare @cursorValoresPkFieldAux varchar(750)
declare @vWhere nvarchar(max)
declare @valorAux nvarchar(max)

--Tabla temporal para guardar y mostrar los resultados
create table #objetosTocados (
	ID_ORGANIZATION nvarchar(4) collate database_default NOT NULL DEFAULT ('0000'),
	ID_TABLA nvarchar(30) collate database_default NOT NULL,
	PK1 nvarchar(400) collate database_default NOT NULL,
	FECHA datetime NOT NULL,
	ID_CLASS nvarchar(50) collate database_default NULL,
	USUARIO nvarchar(30) collate database_default NULL,
	TIPO_TRANSFER nvarchar(1) collate database_default NULL,
	ID_APPROLE nvarchar(30) collate database_default NULL,
	ID_SECUSER nvarchar(30) collate database_default NULL,
	DT_LAST_UPDATE datetime NULL,
	ID_REAL_OBJECT_LECTURA nvarchar(50) collate database_default NULL,
	CAMPOS_PK1 nvarchar(400) collate database_default NOT NULL,
	SENTENCE nvarchar(max) collate database_default NULL,

	PRIMARY KEY (ID_TABLA, PK1,	FECHA, ID_ORGANIZATION)
) 

--Creamos la tabla donde pondremos las tablas de las que queremos escanear
DECLARE @TABLAS_ESCANEAR TABLE (
	ID_ORGANIZATION nvarchar(4) NOT NULL,
	ID_CLASS nvarchar(50) NOT NULL,
	ID_REAL_OBJECT nvarchar(50) NOT NULL,
	ID_PK_FIELD1 nvarchar(400) NULL,
	ID_APPROLE nvarchar(30) NULL,
	ID_SECUSER nvarchar(30) NULL,
	DT_LAST_UPDATE datetime NULL,
	TIPO_TRANSFER nvarchar(1) NULL,
	ID_REAL_OBJECT_LECTURA nvarchar(50) NULL,
	
	PRIMARY KEY (ID_CLASS, ID_REAL_OBJECT, ID_ORGANIZATION)
)


--Creamos la tabla donde pondremos las clases que queremos excluir
DECLARE @CLASES_EXCLUIDAS TABLE (
	ID_ORGANIZATION nvarchar(4) NOT NULL DEFAULT ('0000'),
	ID_CLASS nvarchar(50) NOT NULL,
	ID_APPROLE nvarchar(30) NULL,
	ID_SECUSER nvarchar(30) NULL,
	DT_LAST_UPDATE datetime NULL,
	EXCLUIDO nvarchar(1) NULL,
	
	PRIMARY KEY (ID_CLASS, ID_ORGANIZATION)
)

--Creamos la tabla donde pondremos los objetos modificados agrupados 
DECLARE @objetosModificadosAgrupados TABLE (
	
	ID_CLASS nvarchar(50) NOT NULL,
	ID_TABLA nvarchar(50) NOT NULL,
	PK1 nvarchar(400) NOT NULL,
	FECHA datetime NOT NULL,
	TIPO_TRANSFER nvarchar(1) NOT NULL,
	USUARIO nvarchar(30) NOT NULL,
	CAMPOS_PK1 nvarchar(400) NOT NULL,
	
	PRIMARY KEY (ID_CLASS, ID_TABLA, USUARIO, PK1, TIPO_TRANSFER, FECHA)

	--ID_CLASS as idClass, ID_TABLA as idObjeto, PK1 as valorObjeto, CONVERT(varchar,MAX(FECHA),23) as fecha, TIPO_TRANSFER as tipoTransfer, USUARIO as usuario, CAMPOS_PK1 as camposObjeto
)

--Creamos la tabla donde pondremos el detalle de los elementos que se se han modificado
DECLARE @itemsDetalle TABLE (

	ID_CLASS nvarchar(50) collate database_default NOT NULL,
	ID_OBJETO nvarchar(100) collate database_default NOT NULL,
	ID_ITEM nvarchar(100) collate database_default NOT NULL,
	TIPO_ITEM nvarchar(30) collate database_default NULL,
	USUARIO nvarchar(30) collate database_default NULL,
	FECHA datetime NOT NULL,
	
	PRIMARY KEY (ID_CLASS, ID_OBJETO, ID_ITEM)
)

--Variables para el cursor que recorrerá la tabla @TABLAS_ESCANEAR
declare @cursorIdOrganization varchar(4)
declare @cursorIdClass nvarchar(50)
declare @cursorIdRealObject nvarchar(50)
declare @cursorIdPkField1 nvarchar(max)
declare @cursorIdAppRole nvarchar(30)
declare @cursorIdSecuser nvarchar(30)
declare @cursorDtLastUpdate datetime
declare @cursorTipoTransfer nvarchar(1)
declare @cursorIdRealObjectLectura nvarchar(50)
declare @cursorValoresPkField1 nvarchar(max)


/****************************************************************************
			INSERCION DE DATOS EN LAS TABLAS A ESCANEAR Y A EXCLUIR
****************************************************************************/
--OBJETOS LOGICOS


------REPLACES


------Esto por si queremos excluir alguna clase 


/******************************************************
			OBTENCION DE OBJETOS MODIFICADOS
******************************************************/

--select de los datos que usaremos en el cursor
declare CursorClassMember
cursor for 
	SELECT ID_ORGANIZATION, ID_CLASS, ID_REAL_OBJECT, ID_PK_FIELD1, 
	ID_APPROLE, ID_SECUSER, DT_LAST_UPDATE, 
	TIPO_TRANSFER, IsNull(ID_REAL_OBJECT_LECTURA,ID_REAL_OBJECT) 
	FROM @TABLAS_ESCANEAR cl
	WHERE NOT EXISTS (
		SELECT 1 FROM @CLASES_EXCLUIDAS excl
		WHERE cl.ID_CLASS = excl.ID_CLASS
		AND excl.EXCLUIDO = 1
	)


open CursorClassMember

--Volcamos el primer registro del cursor a las variables que usaremos
fetch from CursorClassMember into @cursorIdOrganization, @cursorIdClass, @cursorIdRealObject, @cursorIdPkField1, @cursorIdAppRole, @cursorIdSecuser, @cursorDtLastUpdate, @cursorTipoTransfer, @cursorIdRealObjectLectura

while @@fetch_status=0
begin
	--Descomentar para ver los datos del cursor
	--SELECT @cursorIdOrganization, @cursorIdClass, @cursorIdRealObject, @cursorIdPkField1, @cursorIdAppRole, @cursorIdSecuser, @cursorDtLastUpdate, @cursorTipoTransfer, @cursorIdRealObjectLectura
	
	--Si los campos de la PK tienen un | es porque la PK esta compuesta por varios campos y tenemos que separarlos
	If CHARINDEX('|',@cursorIdPkField1) = 0 
	Begin
		set @camposFormateados = @cursorIdPkField1	--Si no tiene | simplemente toma el valor del campo
	End
	Else
	Begin
		-- Procesamos los distintos campos y los concatenaremos en uno solo
		set @cursorIdPkFieldAux = @cursorIdPkField1
		set @camposFormateados = ''
		WHILE CHARINDEX('|',@cursorIdPkFieldAux,0) <> 0 
		begin
			--Guardamos el campo que estamos procesando
			set @campoAux = RTRIM(LTRIM(SUBSTRING(@cursorIdPkFieldAux,1,CHARINDEX('|',@cursorIdPkFieldAux,0)-1)))

			--Obtenemos el tipo de dato del campo
			select @tipoDatoCampoAux = data_type from INFORMATION_SCHEMA.COLUMNS where table_name=@cursorIdRealObjectLectura and column_name = @campoAux
			
			--Concantemamos el campo que estamos tratando
			set @camposFormateados = @camposFormateados + 'convert(varchar(1500), ' + @campoAux + ') + ''|'' + '

			--Eliminamos el campo tratado de la cadena
			set @cursorIdPkFieldAux=RTRIM(LTRIM(SUBSTRING(@cursorIdPkFieldAux,CHARINDEX('|',@cursorIdPkFieldAux,0)+1,LEN(@cursorIdPkFieldAux))))
		end
		--Al salir del bucle aun falta un campo por tratar así que lo añadimos a la cadena
		set @camposFormateados = @camposFormateados + 'convert(varchar(1500), ' + @cursorIdPkFieldAux + ')'
	End
	
	--select @camposFormateados, @cursorIdRealObjectLectura, @cursorIdPkField1
	set @sql = 'insert into #objetosTocados (ID_ORGANIZATION, ID_TABLA, PK1, FECHA, USUARIO, ID_CLASS, TIPO_TRANSFER, CAMPOS_PK1)'
    set @sql = @sql + ' select distinct ''0000'', ''' + @cursorIdRealObject + ''',' + @camposFormateados + ', '
    set @sql = @sql + ' ISNULL(DATEADD(MILLISECOND, -DATEPART(MILLISECOND , DT_LAST_UPDATE ), DT_LAST_UPDATE ),''18000101''), '
    set @sql = @sql + ' ID_SECUSER, ''' + @cursorIdClass + ''', ''' + @cursorTipoTransfer + ''',''' + @cursorIdPkField1 + ''' from '
    set @sql = @sql + @cursorIdRealObjectLectura
  	set @sql = @sql + ' WHERE DT_LAST_UPDATE >= @fechaInicioFiltro'
	set @sql = @sql + ' AND DT_LAST_UPDATE <= @fechaFinFiltro + 1' --Sumamos un dia a la fecha de fin porque los campos son fecha y hora
    
	
	EXEC sp_executesql @sql, N'@fechaInicioFiltro datetime, @fechaFinFiltro datetime',@fechaInicioFiltro,@fechaFinFiltro
	
	--Volcamos el siguiente registro del cursor a las variables que usaremos
	fetch from CursorClassMember into @cursorIdOrganization, @cursorIdClass, @cursorIdRealObject, @cursorIdPkField1, @cursorIdAppRole, @cursorIdSecuser, @cursorDtLastUpdate, @cursorTipoTransfer, @cursorIdRealObjectLectura
end

close CursorClassMember
deallocate CursorClassMember

--Descomentar si se quiere ver los datos puros de objetos modificados
--SELECT * FROM #objetosTocados


--insertamos los objetos modificados agrupados por maxima fecha 
SELECT ID_CLASS as idClass, ID_TABLA as idObjeto, PK1 as valorObjeto, CONVERT(varchar,MAX(FECHA),23) as fecha, TIPO_TRANSFER as tipoTransfer, USUARIO as usuario, CAMPOS_PK1 as camposObjeto
FROM #objetosTocados 
WHERE TIPO_TRANSFER = 'R'
AND USUARIO LIKE @usuarioFiltro
AND PK1 not like 'tmp%'	--Quitamos las presentaciones temporales
AND PK1 NOT LIKE '%#'	--Quitamos las tablas traducidas #
GROUP BY ID_CLASS, ID_TABLA, PK1, TIPO_TRANSFER, USUARIO, CAMPOS_PK1
UNION
SELECT ID_CLASS as idClass, MAX(ID_TABLA) as idObjeto, PK1 as valorObjeto, CONVERT(varchar,MAX(FECHA),23) as fecha, TIPO_TRANSFER as tipoTransfer, MAX(USUARIO) as usuario, MAX(CAMPOS_PK1) as camposObjeto
FROM #objetosTocados 
WHERE TIPO_TRANSFER <> 'R'
AND USUARIO LIKE @usuarioFiltro
AND PK1 not like 'tmp%'	--Quitamos las presentaciones temporales
AND PK1 NOT LIKE '%#'	--Quitamos las tablas traducidas #
GROUP BY ID_CLASS, PK1, TIPO_TRANSFER

--Insertamos el detalle de los items
SELECT DISTINCT  OBJ.ID_CLASS, A.ID_TI, A.ID_ITEM, B.N_ITEM_TPESP, A.ID_SECUSER, CONVERT(varchar,A.DT_LAST_UPDATE,23) AS fechaDetalle
from #objetosTocados OBJ
INNER JOIN 
	(SELECT ID_CLASS, PK1, MAX(FECHA) AS FECHA
		FROM #objetosTocados 
		WHERE TIPO_TRANSFER <> 'R'
		AND USUARIO LIKE @usuarioFiltro
		AND ID_CLASS = 'NODE STRUCTURE'
		AND PK1 not like 'tmp%'	--Quitamos las presentaciones temporales
		AND PK1 NOT LIKE '%#'	--Quitamos las tablas traducidas #
		GROUP BY ID_CLASS, PK1) ULTMOD
ON OBJ.ID_CLASS = ULTMOD.ID_CLASS
AND OBJ.PK1 = ULTMOD.PK1
AND OBJ.FECHA = ULTMOD.FECHA
INNER JOIN M4RCH_ITEMS A on A.ID_TI = OBJ.PK1
INNER JOIN M4RCH_LU_ITEM_TP B ON B.ID_ITEM_TYPE = A.ID_ITEM_TYPE
where 
A.DT_LAST_UPDATE >= @fechaInicioFiltro 
AND A.DT_LAST_UPDATE <= @fechaFinFiltro + 1
UNION
SELECT DISTINCT OBJ.ID_CLASS, R.ID_RULE_TI, R.ID_ITEM, B.N_ITEM_TPESP, R.ID_SECUSER, CONVERT(varchar,R.DT_LAST_UPDATE,23) AS fechaDetalle
 from #objetosTocados OBJ
INNER JOIN 
	(SELECT ID_CLASS, PK1, MAX(FECHA) AS FECHA
		FROM #objetosTocados 
		WHERE TIPO_TRANSFER <> 'R'
		AND USUARIO LIKE @usuarioFiltro
		AND ID_CLASS = 'NODE STRUCTURE'
		AND PK1 not like 'tmp%'	--Quitamos las presentaciones temporales
		AND PK1 NOT LIKE '%#'	--Quitamos las tablas traducidas #
		GROUP BY ID_CLASS, PK1) ULTMOD
ON OBJ.ID_CLASS = ULTMOD.ID_CLASS
AND OBJ.PK1 = ULTMOD.PK1
AND OBJ.FECHA = ULTMOD.FECHA
INNER JOIN M4RCH_RULES R ON R.ID_RULE_TI = OBJ.PK1
INNER JOIN M4RCH_ITEMS I ON (I.ID_TI = R.ID_TI AND I.ID_ITEM = R.ID_ITEM) 
INNER JOIN M4RCH_LU_ITEM_TP B ON (B.ID_ITEM_TYPE= I.ID_ITEM_TYPE )
where R.ID_RULE_TI <> R.ID_TI
AND R.DT_LAST_UPDATE >= @fechaInicioFiltro 
AND R.DT_LAST_UPDATE <= @fechaFinFiltro + 1




