--Json con las tablas escaneadas
select t.ID_REAL_OBJECT as idTabla
,campos.COLUMN_NAME as 'idCampo'
,CASE 
	WHEN campos.DATA_TYPE IN ('int', 'float', 'double', 'numeric') then 'numeric'
	WHEN campos.DATA_TYPE IN ('datetime') then 'datetime'
	ELSE 'string'
END as 'idTipoCampo'
from @TABLAS_ESCANEAR t 
inner join INFORMATION_SCHEMA.COLUMNS campos on (campos.table_name = t.ID_REAL_OBJECT)
order by t.ID_REAL_OBJECT
FOR JSON AUTO, root ('tablas'), INCLUDE_NULL_VALUES 


--Json con los objetos modificados
SELECT ID_CLASS as idClass, ID_TABLA as idObjeto, PK1 as valorObjeto,CONVERT(varchar,FECHA,23) as fecha, TIPO_TRANSFER as tipoTransfer, USUARIO as usuario, CAMPOS_PK1 as camposObjeto
FROM @objetosModificadosAgrupados
FOR JSON AUTO, root ('objetosModificados')

--Json con el detalle de los items de las estructuras de nodo
SELECT detalleItems.ID_CLASS as idClassDetalle, detalleItems.ID_OBJETO as idObjetoDetalle, detalleItems.ID_ITEM as idItemDetalle, detalleItems.USUARIO as usuarioDetalle, CONVERT(varchar,detalleItems.FECHA,23) as fechaDetalle
FROM @itemsDetalle detalleItems
FOR JSON AUTO, root ('detalleItems')

--Borramos las tablas temporales
drop table #objetosTocados
